    inline uint8_t get_AUTOCORR_STATISTIC_AUTOCORR_FAILS() volatile
    {
        return (AUTOCORR_STATISTIC >> 14u) & 0xffu;
    }

    /**
     * Set AUTOCORR_STATISTIC's AUTOCORR_FAILS field.
     *
     * Count each time an autocorrelation test fails. Any write to the register
     * reset the counter. Stop collecting statistic if one of the counters
     * reached the limit.
     */
    inline void set_AUTOCORR_STATISTIC_AUTOCORR_FAILS(uint8_t value) volatile
    {
        uint32_t curr = AUTOCORR_STATISTIC;

        curr &= ~(0xffu << 14u);
        curr |= (value & 0xffu) << 14u;

        AUTOCORR_STATISTIC = curr;
    }

    /**
     * Get AUTOCORR_STATISTIC's RESERVED field.
     *
     * RESERVED
     */
    inline uint16_t get_AUTOCORR_STATISTIC_RESERVED() volatile
    {
        return (AUTOCORR_STATISTIC >> 22u) & 0b1111111111u;
    }

    /**
     * Get all of AUTOCORR_STATISTIC's bit fields.
     *
     * (read-write) Statistic about Autocorrelation test activations.
     */
    inline void get_AUTOCORR_STATISTIC(uint16_t &AUTOCORR_TRYS,
                                       uint8_t &AUTOCORR_FAILS,
                                       uint16_t &RESERVED) volatile
    {
        uint32_t curr = AUTOCORR_STATISTIC;

        AUTOCORR_TRYS = curr & 0b11111111111111u;
        AUTOCORR_FAILS = (curr >> 14u) & 0xffu;
        RESERVED = (curr >> 22u) & 0b1111111111u;
    }

    /**
     * Set all of AUTOCORR_STATISTIC's bit fields.
     *
     * (read-write) Statistic about Autocorrelation test activations.
     */
    inline void set_AUTOCORR_STATISTIC(uint16_t AUTOCORR_TRYS,
                                       uint8_t AUTOCORR_FAILS) volatile
    {
        uint32_t curr = AUTOCORR_STATISTIC;

        curr &= ~(0b11111111111111u);
        curr |= (AUTOCORR_TRYS & 0b11111111111111u);
        curr &= ~(0xffu << 14u);
        curr |= (AUTOCORR_FAILS & 0xffu) << 14u;

        AUTOCORR_STATISTIC = curr;
    }

