    /**
     * Get all of TRNG_DEBUG_CONTROL's bit fields.
     *
     * (read-write) Debug register.
     */
    inline void get_TRNG_DEBUG_CONTROL(bool &RESERVED, bool &VNC_BYPASS,
                                       bool &TRNG_CRNGT_BYPASS,
                                       bool &AUTO_CORRELATE_BYPASS) volatile
    {
        uint32_t curr = TRNG_DEBUG_CONTROL;

        RESERVED = curr & 1u;
        VNC_BYPASS = curr & (1u << 1u);
        TRNG_CRNGT_BYPASS = curr & (1u << 2u);
        AUTO_CORRELATE_BYPASS = curr & (1u << 3u);
    }

    /**
     * Set all of TRNG_DEBUG_CONTROL's bit fields.
     *
     * (read-write) Debug register.
     */
    inline void set_TRNG_DEBUG_CONTROL(bool VNC_BYPASS, bool TRNG_CRNGT_BYPASS,
                                       bool AUTO_CORRELATE_BYPASS) volatile
    {
        uint32_t curr = TRNG_DEBUG_CONTROL;

        curr &= ~(0b1u << 1u);
        curr |= (VNC_BYPASS & 0b1u) << 1u;
        curr &= ~(0b1u << 2u);
        curr |= (TRNG_CRNGT_BYPASS & 0b1u) << 2u;
        curr &= ~(0b1u << 3u);
        curr |= (AUTO_CORRELATE_BYPASS & 0b1u) << 3u;

        TRNG_DEBUG_CONTROL = curr;
    }

